        assert_eq!(stats.rows_inserted, FTS5_BATCH_SIZE * 3 + 50);
        assert_eq!(stats.batches_completed, 4);

        // Verify all data inserted
        let count: i64 = conn.query_row(
            "SELECT COUNT(*) FROM fts5_content", [], |r| r.get(0)
        ).unwrap();
