            Document { rowid: 2, source_path: "/b".into(), content: "python scripting".into() },
            Document { rowid: 3, source_path: "/c".into(), content: "rust systems".into() },
        ];

        batch_insert_fts5(&mut conn, &docs, None).unwrap();

        // FTS5 search should work
        let results: Vec<i64> = conn.prepare("SELECT rowid FROM fts5_content WHERE fts5_content MATCH 'rust'")
