        assert!(results.contains(&3));
    }

    #[test]
    fn test_progress_callback() {
        let mut conn = setup_test_db();
        let docs = make_docs(1000);

        let progress_reports = Arc::new(Mutex::new(Vec::new()));
        let reports_clone = Arc::clone(&progress_reports);

        let progress_fn = move |current: usize, total: usize| {
            reports_clone.lock().unwrap().push((current, total));
        };

        batch_insert_fts5(&mut conn, &docs, Some(&progress_fn)).unwrap();

        let reports = progress_reports.lock().unwrap();
        assert!(!reports.is_empty());

        // Last report should show completion
        let (last_current, last_total) = reports.last().unwrap();
        assert_eq!(*last_current, 1000);
        assert_eq!(*last_total, 1000);
    }

    #[test]
    fn test_stats_calculation() {
        let mut conn = setup_test_db();
        let docs = make_docs(1000);

        let stats = batch_insert_fts5(&mut conn, &docs, None).unwrap();

        assert!(stats.rows_per_second() > 0.0);
        assert!(stats.avg_batch_time() > Duration::ZERO);
        assert_eq!(stats.batch_times.len(), stats.batches_completed);
    }
