fn test_batch_vs_single_insert_equivalence() {
    // Create two databases
    let mut conn_batch = setup_test_db();
    let mut conn_single = setup_test_db();

    let docs = make_docs(500);

    // Batch insert
    batch_insert_fts5(&mut conn_batch, &docs, None).unwrap();

    // Single insert
    for doc in &docs {
        conn_single.execute(
            "INSERT INTO fts5_content (rowid, source_path, content) VALUES (?, ?, ?)",
            params![doc.rowid, doc.source_path, doc.content],
        ).unwrap();
    }

    // Verify identical results for various queries
    let queries = vec!["test", "content", "document", "path"];

    for query in queries {
        let sql = format!("SELECT rowid FROM fts5_content WHERE fts5_content MATCH '{}' ORDER BY rowid", query);

        let batch_results: Vec<i64> = conn_batch.prepare(&sql).unwrap()
            .query_map([], |r| r.get(0)).unwrap()
            .collect::<Result<_, _>>().unwrap();

        let single_results: Vec<i64> = conn_single.prepare(&sql).unwrap()
            .query_map([], |r| r.get(0)).unwrap()
            .collect::<Result<_, _>>().unwrap();

        assert_eq!(batch_results, single_results, 
            "Results differ for query '{}'", query);
    }
