fn benchmark_fts5_insert(c: &mut Criterion) {
    let mut group = c.benchmark_group("fts5_insert");

    for num_docs in [100, 1000, 10000] {
        let docs = make_docs(num_docs);

        group.bench_with_input(
            BenchmarkId::new("single", num_docs),
            &num_docs,
            |b, _| {
                b.iter_with_setup(
                    || setup_test_db(),
                    |mut conn| {
                        for doc in &docs {
                            conn.execute(
                                "INSERT INTO fts5_content (rowid, source_path, content) VALUES (?, ?, ?)",
                                params![doc.rowid, doc.source_path, doc.content],
                            ).unwrap();
                        }
                    }
                )
            },
        );

        group.bench_with_input(
            BenchmarkId::new("batch", num_docs),
            &num_docs,
            |b, _| {
                b.iter_with_setup(
                    || setup_test_db(),
                    |mut conn| batch_insert_fts5(&mut conn, &docs, None).unwrap()
                )
            },
        );
    }

    group.finish();
}
