    let _enter = span.enter();

    tracing::debug!(
        target: "cass::perf::fts5",
        "Starting batch insert of {} documents",
        documents.len()
    );

    let stats = batch_insert_fts5(conn, documents, None)?;

    tracing::info!(
        target: "cass::perf::fts5",
        rows = stats.rows_inserted,
        batches = stats.batches_completed,
        total_ms = stats.total_time.as_millis(),
        rows_per_sec = format!("{:.0}", stats.rows_per_second()),
        "Batch insert complete"
    );

    Ok(stats)
}
