### Sync Method Selection
```rust
pub async fn sync_source(&self, source: &SourceDefinition) -> Result<SyncReport, SyncError> {
    let method = Self::detect_sync_method();
    let dest_dir = self.local_store.join(&source.name);
    std::fs::create_dir_all(&dest_dir)?;

    let mut report = SyncReport::new(&source.name, method);

    for remote_path in &source.paths {
        let result = match method {
            SyncMethod::Rsync => self.sync_path_rsync(source, remote_path, &dest_dir).await,
            SyncMethod::Sftp => self.sync_path_sftp(source, remote_path, &dest_dir).await,
        };
        report.add_path_result(remote_path.clone(), result);
    }

    report
}
```

### Error Recovery
```rust
impl SyncEngine {
    /// Sync continues even if individual paths fail
    pub async fn sync_all(&self) -> Vec<SyncReport> {
        let mut reports = Vec::new();

        for source in &self.config.sources {
            match self.sync_source(source).await {
                Ok(report) => reports.push(report),
                Err(e) => reports.push(SyncReport::failed(&source.name, e)),
            }
        }

        reports
    }
}
```

