+    initAttachments,
+    hasAttachments,
+    getManifest,
+    getMessageAttachments,
+    loadBlob,
+    loadBlobAsUrl,
+    createAttachmentElement,
+    clearCache,
+    reset,
+    getCacheStats,
+};

